+    #[test]
+    fn test_token_store_get_or_refresh_preserves_refresh_token_when_provider_omits_rotation() {
+        run_with_test_runtime(async {
+            let server = MockServer::start().await;
+            Mock::given(method("POST"))
+                .and(path("/token"))
